mapper.select:
WITH RECURSIVE menu_tree AS ( SELECT m.menuId, m.parentMenuId, m.menuName, m.menuLevel, m.menuIcon, m.menuDirYn, m.programId, m.sortOrder, m.useYn, m.site, CAST(CONCAT(LPAD(COALESCE(m.sortOrder, 0), 10, '0'), '_', m.menuId) AS CHAR(1000)) AS treePath, CAST(m.menuName AS CHAR(1000)) AS treeName, 0 AS depth FROM menu_info m WHERE m.menuLevel = 1 AND m.useYn = 'Y'
AND m.site = #{site}
UNION ALL SELECT m.menuId, m.parentMenuId, m.menuName, m.menuLevel, m.menuIcon, m.menuDirYn, m.programId, m.sortOrder, m.useYn, m.site, CONCAT(mt.treePath, ' > ', LPAD(COALESCE(m.sortOrder, 0), 10, '0'), '_', m.menuId) AS treePath, CONCAT(mt.treeName, ' > ', m.menuName) AS treeName, mt.depth + 1 AS depth FROM menu_info m INNER JOIN menu_tree mt ON m.parentMenuId = mt.menuId WHERE m.useYn = 'Y'
AND m.site = #{site}
) SELECT mt.depth, CONCAT(REPEAT(' ', mt.depth), mt.menuName) AS menuNameTree, mt.menuId, mt.menuName, mt.parentMenuId, mt.menuLevel, mt.menuIcon, mt.menuDirYn, mt.programId, mt.sortOrder, mt.useYn, mt.site, mt.treePath, p.programName, p.programUrl FROM menu_tree mt LEFT JOIN program_info p ON mt.programId = p.programId AND p.useYn = 'Y'
AND mt.menuId LIKE CONCAT('%', #{menuId}, '%')
AND mt.menuName LIKE CONCAT('%', #{menuName}, '%')
ORDER BY mt.treePath

WITH RECURSIVE menu_tree AS ( SELECT m.menuId, m.parentMenuId, m.menuName, m.menuLevel, m.menuIcon, m.menuDirYn, m.programId, m.sortOrder, m.useYn, m.site, CAST(m.menuId AS CHAR(1000)) AS treePath, CAST(m.menuName AS CHAR(1000)) AS treeName, 0 AS depth FROM menu_info m WHERE m.parentMenuId IS NULL AND m.useYn = 'Y' AND m.menuDirYn = 'Y'
AND m.site = #{site}
UNION ALL SELECT m.menuId, m.parentMenuId, m.menuName, m.menuLevel, m.menuIcon, m.menuDirYn, m.programId, m.sortOrder, m.useYn, m.site, CONCAT(mt.treePath, ' > ', m.menuId) AS treePath, CONCAT(mt.treeName, ' > ', m.menuName) AS treeName, mt.depth + 1 AS depth FROM menu_info m INNER JOIN menu_tree mt ON m.parentMenuId = mt.menuId WHERE m.useYn = 'Y' AND m.menuDirYn = 'Y' AND mt.depth < 1
AND m.site = #{site}
) SELECT mt.depth, CONCAT(REPEAT(' ', mt.depth), mt.menuName) AS menuNameTree, mt.menuId, mt.parentMenuId, mt.menuLevel, mt.menuIcon, mt.menuDirYn, mt.programId, mt.sortOrder, mt.useYn, mt.site, mt.treePath, NULL AS programName, NULL AS programUrl FROM menu_tree mt ORDER BY mt.treePath, mt.sortOrder
